import React, { useEffect, useState } from 'react';
import './HowItWorks.css';

const steps = [
  {
    step: '01',
    title: '가입하고 바로 시작',
    desc: '회원가입 후 웹 또는 데스크톱에서 바로 메이티를 사용할 수 있습니다.',
    detail: '설치부터 첫 대화까지 최대한 짧고 부드럽게 설계했습니다.',
  },
  {
    step: '02',
    title: 'AI 친구를 고르기',
    desc: '하루와 루미 중 원하는 캐릭터를 선택하고 대화 스타일을 맞춥니다.',
    detail: '성향, 말투, 감정 반응 강도를 조정해 더 자연스러운 상호작용을 만듭니다.',
  },
  {
    step: '03',
    title: '일상 속 대화 축적',
    desc: '메이티는 대화 흐름과 감정 패턴을 기억하며 점점 더 나에게 맞춰집니다.',
    detail: '하루하루의 감정 변화를 인사이트로 연결해줍니다.',
  },
  {
    step: '04',
    title: '먼저 반응하는 경험',
    desc: '필요한 순간 메이티가 먼저 말을 걸고, 감정 케어 경험을 이어갑니다.',
    detail: '단순 응답이 아니라 타이밍과 맥락까지 고려한 제품 경험입니다.',
  },
];

const scenarios = [
  {
    title: '야근 후 감정 소진',
    tag: 'Work Stress',
    colorClass: 'blue',
    bgLabel: 'Late Night Work Session',
    message:
      '오늘도 오래 버텼네요. 많이 애쓴 하루였어요. 지금 제일 무거운 감정은 어떤 건가요?',
    choices: ['피곤함이 커요', '마음이 답답해요'],
    insight: '피로 누적 + 정서적 소진',
    image: '/images/rabbit.png',
    character: '하루',
    role: '차분하고 따뜻한 공감형',
  },
  {
    title: '취업 준비 중 불안',
    tag: 'Future Anxiety',
    colorClass: 'pink',
    bgLabel: 'Career Search Context',
    message:
      '계속 버티고 있다는 것만으로도 충분히 대단해요. 지금 가장 불안한 지점이 어디인지 같이 볼까요?',
    choices: ['결과가 두려워요', '자꾸 비교하게 돼요'],
    insight: '불안 + 자기비교 경향',
    image: '/images/cat.png',
    character: '루미',
    role: '밝고 다정한 에너지형',
  },
  {
    title: '혼자 있는 밤의 외로움',
    tag: 'Lonely Evening',
    colorClass: 'purple',
    bgLabel: 'Quiet Night Context',
    message:
      '밤이 되면 감정이 더 크게 느껴질 때가 있죠. 지금은 그냥 옆에서 들어드릴게요.',
    choices: ['조금 외로워요', '생각이 많아졌어요'],
    insight: '고립감 + 생각 과부하',
    image: '/images/rabbit.png',
    character: '하루',
    role: '차분하고 따뜻한 공감형',
  },
];

function HowItWorks() {
  const [activeScenario, setActiveScenario] = useState(0);
  const [typedMessage, setTypedMessage] = useState('');
  const [showChoices, setShowChoices] = useState(false);

  const current = scenarios[activeScenario];

  useEffect(() => {
    setTypedMessage('');
    setShowChoices(false);

    let i = 0;
    const timer = setInterval(() => {
      if (i < current.message.length) {
        setTypedMessage(current.message.slice(0, i + 1));
        i += 1;
      } else {
        clearInterval(timer);
        setTimeout(() => setShowChoices(true), 280);
      }
    }, 22);

    return () => clearInterval(timer);
  }, [activeScenario, current.message]);

  useEffect(() => {
    const cards = document.querySelectorAll('.hiw-step-card');
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          entry.target.classList.add('visible');
          observer.unobserve(entry.target);
        });
      },
      { threshold: 0.12 }
    );

    cards.forEach((card) => observer.observe(card));
    return () => observer.disconnect();
  }, []);

  return (
    <section className="how-it-works page-section" id="how-it-works">
      <div className="container">
        <div className="section-header">
          <div className="section-badge">이용 방법</div>
          <h2 className="section-title">
            복잡하지 않게,
            <br />
            <span className="gradient-text">4단계로 시작하세요</span>
          </h2>
          <p className="section-subtitle">
            처음 만나는 순간부터 일상 속에 자연스럽게 스며들기까지,
            메이티의 경험 흐름을 제품 중심으로 설계했습니다.
          </p>
        </div>

        <div className="hiw-steps-grid">
          {steps.map((item, index) => (
            <article
              key={item.step}
              className="hiw-step-card reveal-up"
              style={{ transitionDelay: `${index * 80}ms` }}
            >
              <div className="hiw-step-top">
                <div className="hiw-step-number">{item.step}</div>
                <div className="hiw-step-line"></div>
              </div>

              <h3>{item.title}</h3>
              <p className="hiw-step-desc">{item.desc}</p>
              <p className="hiw-step-detail">{item.detail}</p>
            </article>
          ))}
        </div>

        <div className="hiw-scenario-block">
          <div className="hiw-scenario-copy">
            <div className="section-badge">실제 시나리오</div>
            <h3 className="hiw-scenario-title">
              메이티는 이런 순간에
              <br />
              <span className="gradient-text">먼저 다가옵니다</span>
            </h3>
            <p className="hiw-scenario-desc">
              단순히 질문에 답하는 AI가 아니라, 감정이 흔들리는 순간을 더 자연스럽게
              포착하고 맥락에 맞는 말로 대화를 시작합니다.
            </p>

            <div className="hiw-scenario-tabs">
              {scenarios.map((scenario, index) => (
                <button
                  key={scenario.title}
                  className={`hiw-scenario-tab ${
                    activeScenario === index ? 'active' : ''
                  } ${scenario.colorClass}`}
                  onClick={() => setActiveScenario(index)}
                >
                  <div className="hiw-tab-copy">
                    <span className="hiw-tab-tag">{scenario.tag}</span>
                    <strong>{scenario.title}</strong>
                  </div>
                  <span className="hiw-tab-arrow">↗</span>
                </button>
              ))}
            </div>
          </div>

          <div className="hiw-preview-wrap">
            <div className={`hiw-preview-shell ${current.colorClass}`}>
              <div className="hiw-preview-top">
                <div className="hiw-preview-dots">
                  <span className="red"></span>
                  <span className="yellow"></span>
                  <span className="green"></span>
                </div>

                <div className="hiw-preview-label">{current.bgLabel}</div>

                <div className="hiw-preview-time">AI Context Active</div>
              </div>

              <div className="hiw-preview-screen">
                <div className="hiw-preview-bg">
                  <div className="hiw-preview-panel code">
                    <div className="panel-title">Screen Context</div>
                    <div className="panel-lines">
                      <span></span>
                      <span></span>
                      <span className="short"></span>
                    </div>
                  </div>

                  <div className="hiw-preview-panel status">
                    <div className="panel-title">Emotion Signal</div>
                    <div className="signal-row">
                      <span>피로</span>
                      <span>불안</span>
                      <span>회복 필요</span>
                    </div>
                  </div>
                </div>

                <div className={`hiw-chat-card glow-ring ${current.colorClass}`}>
                  <div className="hiw-chat-top">
                    <div className="hiw-chat-avatar">
                      <img src={current.image} alt={current.character} />
                    </div>

                    <div className="hiw-chat-copy">
                      <strong>{current.character}</strong>
                      <span>{current.role}</span>
                    </div>

                    <div className="hiw-chat-chip">{current.tag}</div>
                  </div>

                  <div className="hiw-chat-body">
                    <div className="hiw-chat-bubble ai">
                      {typedMessage}
                      {typedMessage.length < current.message.length && (
                        <span className="hiw-typing-cursor">▌</span>
                      )}
                    </div>

                    {showChoices && (
                      <div className="hiw-choice-list">
                        {current.choices.map((choice, idx) => (
                          <button
                            key={`${choice}-${idx}`}
                            className="hiw-choice-btn"
                            style={{ animationDelay: `${idx * 90}ms` }}
                          >
                            {choice}
                          </button>
                        ))}
                      </div>
                    )}

                    <div className="hiw-insight-card">
                      <span className="insight-label">Detected Insight</span>
                      <strong>{current.insight}</strong>
                    </div>
                  </div>

                  <div className="hiw-floating-note left">맥락 기반 시작</div>
                  <div className="hiw-floating-note right">감정 인사이트 반영</div>
                </div>

                <div className="hiw-taskbar">
                  <div className="hiw-taskbar-left">🪟</div>
                  <div className="hiw-taskbar-center">
                    <span className="active">Matey</span>
                    <span>Reflection</span>
                    <span>Notes</span>
                  </div>
                  <div className="hiw-taskbar-right">22:14</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default HowItWorks;
